/* ─── Helpers ─────────────────────────────────────────── */

// Retorna o profile de um cliente (ou null se não cadastrado).
// Aceita id principal (bioter) ou id de unidade (bioter_chapeco).
function getClientProfile(id){
  if(!id)return null;
  if(CLIENT_PROFILES[id])return CLIENT_PROFILES[id];
  // É unidade do Bioter?
  const unit=BIOTER_GROUP_UNITS.find(function(u){return u.id===id;});
  if(unit)return unit;
  return null;
}

// MRR total do Grupo Bioter — soma das unidades.
function getBioterGroupMRR(){
  return BIOTER_GROUP_UNITS.reduce(function(acc,u){return acc+(u.mrr||0);},0);
}

// MRR total da agência (soma de todos os clientes ativos).
function getAgencyTotalMRR(){
  let total=0;
  // Grupo Bioter (soma das unidades)
  total+=getBioterGroupMRR();
  // Demais clientes (com mrr próprio)
  ["construschorr","arabuta","climaves","vetservice"].forEach(function(id){
    const p=CLIENT_PROFILES[id];
    if(p&&p.status!=="encerrado"&&p.status!=="pausado")total+=p.mrr||0;
  });
  return total;
}

// Formata BRL pra exibição.
function fmtBRLClient(n){
  if(typeof n!=="number"||isNaN(n))return "—";
  return "R$ "+n.toLocaleString("pt-BR",{minimumFractionDigits:0,maximumFractionDigits:2});
}

// Helper visual: pega config de status (cor, label, bg)
function getStatusConfig(statusId){
  return CLIENTE_STATUS_OPTS.find(function(s){return s.id===statusId;})||CLIENTE_STATUS_OPTS[1];
}

/* ─── TIMELINE DE MARCOS — estilo Asana ──────────────────
   Linha do tempo de eventos por cliente: visitas, materiais
   de feira, reuniões, campanhas, contratos, etc.
   Armazenado em localStorage["pixels-marcos-<clientId>"] —
   array de marcos. Migra pra Supabase depois.
─────────────────────────────────────────────────────── */
const MARCO_TYPES = [
  {id:"visita",    label:"Visita",         color:"#0284c7", bg:"#e0f2fe"},
  {id:"reuniao",   label:"Reunião",        color:"#7c3aed", bg:"#f5f3ff"},
  {id:"feira",     label:"Feira / evento", color:"#ea580c", bg:"#ffedd5"},
  {id:"material",  label:"Material",       color:"#16a34a", bg:"#dcfce7"},
  {id:"campanha",  label:"Campanha",       color:"#0891b2", bg:"#cffafe"},
  {id:"contrato",  label:"Contrato",       color:"#0f172a", bg:"#e2e8f0"},
  {id:"outro",     label:"Outro",          color:"#64748b", bg:"#f1f5f9"},
];

function getMarcoTypeConfig(typeId){
  return MARCO_TYPES.find(function(t){return t.id===typeId;})||MARCO_TYPES[MARCO_TYPES.length-1];
}

// Carrega marcos de um cliente (localStorage)
function loadMarcos(clientId){
  if(!clientId)return [];
  try{
    const raw=localStorage.getItem("pixels-marcos-"+clientId);
    if(!raw)return [];
    const parsed=JSON.parse(raw);
    if(!Array.isArray(parsed))return [];
    return parsed.sort(function(a,b){return (b.date||"").localeCompare(a.date||"");});
  }catch(e){return [];}
}

// Salva marcos no localStorage. Dispara evento pra outros componentes recarregarem.
function saveMarcos(clientId, marcos){
  if(!clientId)return;
  try{
    localStorage.setItem("pixels-marcos-"+clientId,JSON.stringify(marcos||[]));
    window.dispatchEvent(new CustomEvent("pixels:marcos-updated",{detail:{clientId:clientId}}));
  }catch(e){console.warn("[marcos] save:",e?.message||e);}
}

// Cria novo marco — gera id único.
function buildMarco(input){
  return Object.assign({
    id:"m"+Date.now()+"-"+Math.random().toString(36).slice(2,6),
    date:new Date().toISOString().slice(0,10),
    type:"outro",
    title:"",
    description:"",
    author:(typeof CURRENT_USER!=="undefined"&&CURRENT_USER&&CURRENT_USER.id)||"",
    createdAt:new Date().toISOString(),
  }, input||{});
}

/* ─── PACOTE DE POSTS POR CLIENTE ─────────────────────
   Quantidade de publicações que cada cliente recebe por semana.
   Default: 1 arte + 1 vídeo = 2 posts/semana.
   Tipos de slot: arte, video, collab, foto (foto-obra).
   Flag fotoObraQuinzenal: a cada 2 semanas, 1 slot vira foto-obra
   substituindo um arte/video.
   Override por cliente via localStorage["pixels-posts-config-<clientId>"].
─────────────────────────────────────────────────────── */
const POSTS_PADRAO = {arte:1, video:1, collab:0, foto:0, videoShort:0, fotoOrShortAlternado:false, fotoObraQuinzenal:false};

// Presets específicos por unidade Bioter (sobrescreve o default)
// Principais (3/semana): 1 arte + 1 vídeo + 1 collab (foto-obra quinzenal substitui o vídeo)
// Filiais (2/semana): 1 arte + 1 collab
// "Collab" aqui é alocado a partir de cards com bioterUnit="grupo" ou "brasil"
// (cards de Grupo Bioter / Bioter Brasil servem como collab pra todas as unidades).
const BIOTER_POSTS_PRESETS = {
  // Principais: 3 posts/sem = 1 collab + 1 foto-de-obra + 1 vídeo-short-do-drive
  bioter_chapeco:    {arte:0, video:0, collab:1, foto:1, videoShort:1, fotoOrShortAlternado:false, fotoObraQuinzenal:false},
  bioter_castro:     {arte:0, video:0, collab:1, foto:1, videoShort:1, fotoOrShortAlternado:false, fotoObraQuinzenal:false},
  bioter_toledo:     {arte:0, video:0, collab:1, foto:1, videoShort:1, fotoOrShortAlternado:false, fotoObraQuinzenal:false},
  // Filiais: 2 posts/sem = 1 collab + 1 alternando (foto-de-obra/vídeo-short)
  bioter_gloria:     {arte:0, video:0, collab:1, foto:0, videoShort:0, fotoOrShortAlternado:true,  fotoObraQuinzenal:false},
  bioter_paraguay:   {arte:0, video:0, collab:1, foto:0, videoShort:0, fotoOrShortAlternado:true,  fotoObraQuinzenal:false},
  bioter_uberlandia: {arte:0, video:0, collab:1, foto:0, videoShort:0, fotoOrShortAlternado:true,  fotoObraQuinzenal:false},
};
// Helper: identifica se um card é "collab" baseado no bioterUnit
// (Grupo Bioter / Bioter Brasil servem como collab pras unidades individuais).
function isBioterCollabCard(task){
  if(!task||task.client!=="bioter")return false;
  const unit=task.bioterUnit;
  // Multi-select: pode ser "grupo,brasil" ou só "grupo"/"brasil"
  if(typeof unit!=="string")return false;
  const ids=unit.split(",").map(function(s){return s.trim();});
  return ids.indexOf("grupo")>=0||ids.indexOf("brasil")>=0;
}

function getPostsConfig(clientId){
  if(!clientId)return Object.assign({},POSTS_PADRAO);
  // 1. Tem override salvo no localStorage?
  try{
    const raw=localStorage.getItem("pixels-posts-config-"+clientId);
    if(raw){const p=JSON.parse(raw);if(p&&typeof p==="object")return Object.assign({},POSTS_PADRAO,p);}
  }catch(e){}
  // 2. É unidade Bioter? Usa preset
  if(BIOTER_POSTS_PRESETS[clientId])return Object.assign({},POSTS_PADRAO,BIOTER_POSTS_PRESETS[clientId]);
  return Object.assign({},POSTS_PADRAO);
}
function savePostsConfig(clientId, cfg){
  if(!clientId)return;
  try{localStorage.setItem("pixels-posts-config-"+clientId,JSON.stringify(Object.assign({},POSTS_PADRAO,cfg||{})));}catch(e){}
}

// Calcula as datas sugeridas pra um mês.
// Retorna [{date:"YYYY-MM-DD", type:"arte"|"video"|"collab"|"foto"}].
// Se fotoObraQuinzenal=true, a cada 2 semanas substitui 1 slot por foto-obra.
function generateMonthPlanDates(year, month, postsConfig){
  const cfg=postsConfig||POSTS_PADRAO;
  const result=[];
  const firstDay=new Date(year, month-1, 1);
  const lastDay=new Date(year, month, 0);
  const cur=new Date(firstDay);
  while(cur.getDay()!==1){cur.setDate(cur.getDate()-1);}
  // Slots: seg=2ª, qua=4ª, qui=5ª (ordem visual); pra 3 posts/semana usa essas 3.
  // Pra 2 posts/semana usa 2ª e 5ª.
  let weekIndex=0;
  while(cur<=lastDay){
    let artes=cfg.arte||0, videos=cfg.video||0, collabs=cfg.collab||0;
    let fotos=cfg.foto||0, shorts=cfg.videoShort||0;
    // Legacy: quinzenal vira 1 vídeo em foto a cada 2 semanas
    if(cfg.fotoObraQuinzenal&&weekIndex%2===0){
      if(videos>0){videos--;fotos++;}else if(artes>0){artes--;fotos++;}
    }
    // Filiais Bioter: 1 slot adicional alternando foto/short (semana par=foto, ímpar=short)
    if(cfg.fotoOrShortAlternado){
      if(weekIndex%2===0)fotos++; else shorts++;
    }
    const totalSemana=artes+videos+collabs+fotos+shorts;
    if(totalSemana<=0){weekIndex++;cur.setDate(cur.getDate()+7);continue;}
    // Distribuição em dias úteis: começa seg, qua, sex
    const dayOrder=[1,3,5,2,4]; // 2ª, 4ª, 6ª (priorizando), depois 3ª e 5ª
    let slotIdx=0;
    while((artes>0||videos>0||collabs>0||fotos>0||shorts>0)&&slotIdx<dayOrder.length){
      const dayOffset=dayOrder[slotIdx]-1;
      const d=new Date(cur);d.setDate(d.getDate()+dayOffset);
      if(d.getMonth()===month-1&&d>=firstDay){
        const ds=d.toISOString().slice(0,10);
        // Ordem preferencial: collab → foto → short → arte → video
        let type;
        if(collabs>0){type="collab";collabs--;}
        else if(fotos>0){type="foto";fotos--;}
        else if(shorts>0){type="video_short";shorts--;}
        else if(artes>=videos&&artes>0){type="arte";artes--;}
        else if(videos>0){type="video";videos--;}
        else if(artes>0){type="arte";artes--;}
        else break;
        result.push({date:ds, type:type});
      }
      slotIdx++;
    }
    weekIndex++;
    cur.setDate(cur.getDate()+7);
  }
  return result.sort(function(a,b){return a.date.localeCompare(b.date);});
}

