function CollabProfileModal({user,onClose,livePerms,setLivePerms,tasks:propTasks}){
  // Prioridade: livePerms (localStorage) → ACCESS_STORE (padrão hardcoded) → DEFAULT_PERMS
  const [perms,setPerms]=useState(()=>({
    ...DEFAULT_PERMS,
    ...(ACCESS_STORE[user.id]||{}),
    ...(livePerms?.[user.id]||{}),
  }));
  const [saved,setSaved]=useState(false);
  const [activeTab,setActiveTab]=useState("dashboard");
  const savedTimer=useRef(null);
  const isPartnerUser=user.level===1;

  const flashSaved=()=>{
    if(savedTimer.current)clearTimeout(savedTimer.current);
    setSaved(true);
    savedTimer.current=setTimeout(()=>setSaved(false),2500);
  };

  const toggle=(key)=>{
    if(isPartnerUser)return; // sócios sempre têm tudo
    setPerms(p=>({...p,[key]:!p[key]}));
    setSaved(false);
  };

  const save=async()=>{
    // 1. Atualiza memória e localStorage imediatamente
    ACCESS_STORE[user.id]={...perms};
    if(setLivePerms) setLivePerms(p=>({...p,[user.id]:{...perms}}));
    try{localStorage.setItem(`pixels-perms-${user.id}`,JSON.stringify(perms));}catch(e){}

    // 2. Salva no Supabase — busca o perfil pelo team_id para obter o UUID real
    try{
      // Primeiro busca o UUID real do perfil pelo team_id
      const {data:profileRow,error:findErr}=await _sb
        .from("profiles")
        .select("id")
        .eq("team_id",user.id)
        .single();

      if(findErr||!profileRow){
        // Perfil não existe — tenta fazer upsert pelo team_id diretamente
        await _sb
          .from("profiles")
          .upsert({team_id:user.id, name:user.name, permissions:perms},{onConflict:"team_id"});
        flashSaved();
        return;
      }

      // Atualiza pelo UUID real (sempre funciona independente de RLS por team_id)
      await _sb
        .from("profiles")
        .update({permissions:perms})
        .eq("id",profileRow.id);

    }catch(e){}

    flashSaved();
  };

  const tasks=(propTasks||[]).filter(t=>t.assignee===user.id);
  const done=tasks.filter(t=>t.status==="aprovado");
  const open=tasks.filter(t=>t.status!=="aprovado"&&t.status!=="pausado");
  const late=open.filter(t=>daysLeft(t.deadline)<0);

  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.9)",zIndex:300,display:"flex",alignItems:"center",justifyContent:"center",padding:"16px"}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:C.card,border:`2px solid ${user.color}`,borderRadius:22,width:"100%",maxWidth:680,maxHeight:"92vh",overflowY:"auto",display:"flex",flexDirection:"column",boxShadow:`0 0 60px ${user.color}30`}}>

      {/* Header */}
      <div style={{background:`linear-gradient(135deg,${user.color},${user.color}88)`,padding:"20px 24px",borderRadius:"20px 20px 0 0",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,zIndex:10}}>
        <div style={{display:"flex",alignItems:"center",gap:14}}>
          <div style={{width:52,height:52,borderRadius:16,background:"rgba(255,255,255,0.2)",border:"2px solid rgba(255,255,255,0.4)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,fontWeight:900,color:"#fff"}}>{user.av}</div>
          <div>
            <div style={{color:"#fff",fontWeight:900,fontSize:18}}>{user.name}</div>
            <div style={{color:"rgba(255,255,255,0.8)",fontSize:12,marginTop:2}}>{user.role} · Nível {user.level}</div>
          </div>
        </div>
        <button onClick={onClose} style={{background:"rgba(0,0,0,0.3)",border:"none",borderRadius:10,padding:"7px 13px",color:"#fff",cursor:"pointer",fontWeight:700}}>✕</button>
      </div>

      {/* Quick stats */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,padding:"16px 24px 0"}}>
        {[
          {l:"Demandas",v:tasks.length,c:user.color},
          {l:"Abertas",v:open.length,c:C.yw},
          {l:"Aprovadas",v:done.length,c:C.gr},
          {l:"Atrasadas",v:late.length,c:late.length>0?C.rd:C.td},
        ].map(s=><div key={s.l} style={{background:`linear-gradient(135deg,${s.c}22,${s.c}0a)`,border:`1px solid ${s.c}33`,borderRadius:12,padding:"10px 8px",textAlign:"center"}}>
          <div style={{color:s.c,fontWeight:900,fontSize:20}}>{s.v}</div>
          <div style={{color:C.td,fontSize:10,marginTop:2}}>{s.l}</div>
        </div>)}
      </div>

      {/* Tab Navigation */}
      <div style={{display:"flex",gap:0,overflowX:"auto",borderBottom:`1px solid ${C.b1}`,background:C.s1,flexShrink:0}}>
        {PERM_TABS.map(tab=>{
          const items=PERM_GROUPS[tab.id]||[];
          const activeItems=items.filter(i=>i.key&&(isPartnerUser?true:perms[i.key]));
          const totalKeys=items.filter(i=>i.key).length;
          const isActive=activeTab===tab.id;
          return <button key={tab.id} onClick={()=>setActiveTab(tab.id)}
            style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2,padding:"10px 14px",background:isActive?C.card:"transparent",border:"none",borderBottom:isActive?`2px solid ${tab.color}`:"2px solid transparent",color:isActive?tab.color:C.ts,cursor:"pointer",whiteSpace:"nowrap",transition:"all .12s",flexShrink:0,marginBottom:-1}}>
            <NavIcon id={tab.navIcon||tab.id} size={16} color={isActive?tab.color:C.ts}/>
            <span style={{fontSize:10,fontWeight:isActive?700:500}}>{tab.label}</span>
            {totalKeys>0&&<span style={{fontSize:8,color:isActive?tab.color:C.td}}>{activeItems.length}/{totalKeys}</span>}
          </button>;
        })}
      </div>

      {/* Permissions — aba ativa */}
      <div style={{padding:"16px 24px 24px",display:"flex",flexDirection:"column",gap:8,overflowY:"auto",flex:1}}>
        {isPartnerUser&&<div style={{background:C.a+"18",border:`1px solid ${C.a}44`,borderRadius:12,padding:"10px 14px",color:C.a,fontSize:12,fontWeight:600}}>⚡ Sócios têm acesso total e irrestrito ao sistema.</div>}

        {(PERM_GROUPS[activeTab]||[]).map((item,idx)=>{
          if(item.section) return <div key={idx} style={{color:C.ts,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:1,marginTop:idx>0?8:0,paddingBottom:6,borderBottom:`1px solid ${C.b1}`}}>{item.section}</div>;
          const on=isPartnerUser?true:(perms[item.key]||false);
          const tabColor=PERM_TABS.find(t=>t.id===activeTab)?.color||user.color;
          return <div key={item.key} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 12px",background:on?tabColor+"10":C.s1,borderRadius:10,border:`1px solid ${on?tabColor+"33":C.b1}`,transition:"all .15s",cursor:isPartnerUser?"default":"pointer"}} onClick={()=>toggle(item.key)}>
            <div style={{flex:1,minWidth:0}}>
              <div style={{color:on?C.tx:C.ts,fontSize:13,fontWeight:on?700:500}}>{item.label}</div>
              <div style={{color:C.td,fontSize:10,marginTop:1}}>{item.desc}</div>
            </div>
            <div style={{width:42,height:24,borderRadius:99,background:on?tabColor:C.b2,cursor:isPartnerUser?"not-allowed":"pointer",position:"relative",transition:"background .2s",flexShrink:0,marginLeft:12}}>
              <div style={{position:"absolute",top:3,left:on?20:3,width:18,height:18,borderRadius:"50%",background:"#fff",transition:"left .2s",boxShadow:"0 1px 4px rgba(0,0,0,0.3)"}}/>
            </div>
          </div>;
        })}

        <button onClick={save} disabled={saved} style={{background:`linear-gradient(135deg,${user.color},${user.color}88)`,color:"#fff",border:"none",borderRadius:12,padding:"14px 0",fontWeight:900,fontSize:15,cursor:saved?"default":"pointer",boxShadow:`0 4px 18px ${user.color}40`,marginTop:10,display:"flex",alignItems:"center",justifyContent:"center",gap:8,opacity:saved?0.8:1}}>
          {saved?<>✓ Permissões Salvas!</>:<>💾 Salvar Permissões</>}
        </button>
      </div>
    </div>
  </div>;
}

/* ─── Constantes estáticas de CollabProfilePage ─── */
const COLLAB_TABS=[
  {id:"dados",icon:"📋",label:"Dados"},
  {id:"pessoal",icon:"🏠",label:"Pessoal"},
  {id:"lazer",icon:"🎮",label:"Lazer"},
  {id:"pets",icon:"🐾",label:"Pets"},
  {id:"curiosidades",icon:"✨",label:"Curiosidades"},
  {id:"bio",icon:"📝",label:"Bio"},
  {id:"seguranca",icon:"🔐",label:"Segurança",selfOnly:true},
];

/* ─── LBL — fora do componente para evitar remount a cada render ─── */
function LBL({t}){
  return <div style={{color:C.ts,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.8,marginBottom:5}}>{t}</div>;
}

/* ─── COLLAB PROFILE EDIT MODAL ─────────────── */
function CollabProfilePage({user,profile,onSave,onClose}){
  const [activeTab,setActiveTab]=useState("dados");
  const p=profile||{};
  const inp={background:C.s1,border:"1px solid "+C.b1,borderRadius:10,padding:"9px 12px",color:C.tx,fontSize:13,outline:"none",width:"100%",boxSizing:"border-box",fontFamily:"inherit"};
  const fileRef=useRef(null);

  const [nome,setNome]=useState(p.nome||user.name);
  const [funcao,setFuncao]=useState(p.funcao||user.role);
  const [telefone,setTelefone]=useState(p.telefone||"");
  const [email,setEmail]=useState(p.email||user.id+"@pixelsmarketing.com.br");
  const [nascimento,setNascimento]=useState(p.nascimento||"");
  const [photo,setPhoto]=useState(p.photo||null);
  const [cidade,setCidade]=useState(p.cidade||"");
  const [estado,setEstado]=useState(p.estado||"");
  const [camiseta,setCamiseta]=useState(p.camiseta||"");
  const [calcado,setCalcado]=useState(p.calcado||"");
  const [smartphone,setSmartphone]=useState(p.smartphone||"");
  const [time,setTime]=useState(p.time||"");
  const [estadoCivil,setEstadoCivil]=useState(p.estadoCivil||"");
  const [filhos,setFilhos]=useState(p.filhos||"");
  const [comidas,setComidas]=useState(p.comidas||["","","","",""]);
  const [bebida,setBebida]=useState(p.bebida||"");
  const [hobbies,setHobbies]=useState(p.hobbies||"");
  const [musica,setMusica]=useState(p.musica||"");
  const [series,setSeries]=useState(p.series||"");
  const [filmes,setFilmes]=useState(p.filmes||"");
  const [viagens,setViagens]=useState(p.viagens||"");
  const [pets,setPets]=useState(p.pets||[{...EMPTY_PET}]);
  const addPet=()=>{if(pets.length<10)setPets(v=>[...v,{...EMPTY_PET}]);};
  const removePet=(i)=>setPets(v=>v.filter((_,idx)=>idx!==i));
  const setPetField=(i,k,val)=>setPets(prev=>prev.map((pt,idx)=>idx===i?{...pt,[k]:val}:pt));
  const [curiosidades,setCuriosidades]=useState(p.curiosidades||"");
  const [medoOuFobia,setMedoOuFobia]=useState(p.medoOuFobia||"");
  const [superpoder,setSuperpoder]=useState(p.superpoder||"");
  const [talento,setTalento]=useState(p.talento||"");
  const [licoesAprendidas,setLicoesAprendidas]=useState(p.licoesAprendidas||"");
  const [bio,setBio]=useState(p.bio||"");
  const [habilidades,setHabilidades]=useState(p.habilidades||"");
  const [objetivos,setObjetivos]=useState(p.objetivos||"");
  const [obs,setObs]=useState(p.obs||"");

  const [uploadingPhoto,setUploadingPhoto]=useState(false);
  const handlePhoto=async(e)=>{
    const file=e.target.files?.[0];
    if(!file)return;
    e.target.value="";
    setUploadingPhoto(true);
    try{
      const sb=window._sb;
      const ext=file.name.split(".").pop()||"jpg";
      const path=`avatars/${user.id}-${Date.now()}.${ext}`;
      const{error}=await sb.storage.from("pixels-files").upload(path,file,{upsert:true});
      if(error)throw error;
      const{data}=sb.storage.from("pixels-files").getPublicUrl(path);
      setPhoto(data.publicUrl);
      // Atualiza localStorage imediatamente pra todos os UserAvatar refletirem antes do save final
      try{
        const k="pixels-selfprofile-"+user.id;
        const prev=JSON.parse(localStorage.getItem(k)||"{}");
        localStorage.setItem(k,JSON.stringify(Object.assign({},prev,{photo:data.publicUrl})));
        window.dispatchEvent(new CustomEvent("pixels:photo-updated",{detail:{userId:user.id}}));
      }catch(_){}
    }catch(err){
      console.error("Erro upload foto:",err);
      // Fallback: usar base64 comprimido via canvas
      const canvas=document.createElement("canvas");
      const img=new Image();
      img.onload=()=>{
        const MAX=400;
        const ratio=Math.min(MAX/img.width,MAX/img.height,1);
        canvas.width=Math.round(img.width*ratio);
        canvas.height=Math.round(img.height*ratio);
        canvas.getContext("2d").drawImage(img,0,0,canvas.width,canvas.height);
        const dataUrl=canvas.toDataURL("image/jpeg",0.75);
        setPhoto(dataUrl);
        try{
          const k="pixels-selfprofile-"+user.id;
          const prev=JSON.parse(localStorage.getItem(k)||"{}");
          localStorage.setItem(k,JSON.stringify(Object.assign({},prev,{photo:dataUrl})));
          window.dispatchEvent(new CustomEvent("pixels:photo-updated",{detail:{userId:user.id}}));
        }catch(_){}
      };
      img.src=URL.createObjectURL(file);
    }finally{
      setUploadingPhoto(false);
    }
  };

  const save=()=>{
    onSave(user.id,{nome,funcao,telefone,email,nascimento,photo,cidade,estado,camiseta,calcado,smartphone,time,estadoCivil,filhos,comidas,bebida,hobbies,musica,series,filmes,viagens,pets,curiosidades,medoOuFobia,superpoder,talento,licoesAprendidas,bio,habilidades,objetivos,obs});
    onClose();
  };

  // ═══ Segurança: trocar senha ═══
  const [currentPw,setCurrentPw]=useState("");
  const [newPw,setNewPw]=useState("");
  const [confirmPw,setConfirmPw]=useState("");
  const [showPws,setShowPws]=useState(false);
  const [pwLoading,setPwLoading]=useState(false);
  const [pwMsg,setPwMsg]=useState(null);

  const pwStrength=(()=>{
    const s=newPw;
    if(!s)return null;
    let score=0;
    if(s.length>=8)score++;
    if(s.length>=12)score++;
    if(/[A-Z]/.test(s)&&/[a-z]/.test(s))score++;
    if(/\d/.test(s))score++;
    if(/[^A-Za-z0-9]/.test(s))score++;
    if(score<=2)return{level:"fraca",color:"#dc2626",pct:30};
    if(score<=3)return{level:"média",color:"#eab308",pct:60};
    if(score<=4)return{level:"boa",color:"#16a34a",pct:80};
    return{level:"excelente",color:"#059669",pct:100};
  })();

  const handleChangePassword=async()=>{
    setPwMsg(null);
    if(!currentPw||!newPw||!confirmPw){
      setPwMsg({type:"error",text:"Preencha todos os campos."});return;
    }
    if(newPw.length<8){
      setPwMsg({type:"error",text:"A nova senha deve ter pelo menos 8 caracteres."});return;
    }
    if(newPw!==confirmPw){
      setPwMsg({type:"error",text:"A confirmação não bate com a nova senha."});return;
    }
    if(newPw===currentPw){
      setPwMsg({type:"error",text:"A nova senha tem que ser diferente da atual."});return;
    }
    setPwLoading(true);
    try{
      const sb=window._sb;
      // 1) Verifica a senha atual tentando relogar
      const{data:authData}=await sb.auth.getUser();
      const userEmail=authData?.user?.email;
      if(!userEmail){throw new Error("Email não encontrado na sessão. Faça login novamente.");}
      const{error:loginErr}=await sb.auth.signInWithPassword({email:userEmail,password:currentPw});
      if(loginErr){throw new Error("Senha atual incorreta.");}
      // 2) Atualiza a senha
      const{error:updErr}=await sb.auth.updateUser({password:newPw});
      if(updErr)throw new Error(updErr.message||"Falha ao atualizar a senha.");
      setPwMsg({type:"success",text:"✓ Senha alterada com sucesso! Use a nova senha no próximo login."});
      setCurrentPw("");setNewPw("");setConfirmPw("");
    }catch(e){
      setPwMsg({type:"error",text:e.message||"Erro ao trocar senha."});
    }finally{
      setPwLoading(false);
    }
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.92)",zIndex:400,display:"flex",alignItems:"flex-start",justifyContent:"center",padding:"16px",overflowY:"auto"}} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{background:C.card,borderRadius:22,width:"100%",maxWidth:700,marginTop:8,border:"2px solid "+user.color,boxShadow:"0 0 60px "+user.color+"30"}}>

        <div style={{background:"linear-gradient(135deg,"+user.color+","+user.color+"88)",padding:"20px 24px",borderRadius:"20px 20px 0 0",display:"flex",alignItems:"center",gap:16,position:"sticky",top:0,zIndex:5}}>
          <div onClick={()=>fileRef.current&&fileRef.current.click()} style={{width:64,height:64,borderRadius:18,background:"rgba(255,255,255,0.2)",border:"2px solid rgba(255,255,255,0.5)",overflow:"hidden",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,position:"relative"}}>
            {uploadingPhoto?<span style={{color:"#fff",fontSize:20}}>⏳</span>:photo?(<img src={photo} alt={user.name} style={{width:"100%",height:"100%",objectFit:"cover"}}/>):(<span style={{color:"#fff",fontWeight:900,fontSize:26}}>{user.av}</span>)}
            <div style={{position:"absolute",bottom:0,left:0,right:0,background:"rgba(0,0,0,0.4)",padding:"3px",textAlign:"center",fontSize:9,color:"#fff"}}>📷</div>
          </div>
          <input ref={fileRef} type="file" accept="image/*" onChange={handlePhoto} style={{display:"none"}}/>
          <div style={{flex:1}}>
            <div style={{color:"#fff",fontWeight:900,fontSize:20}}>{nome}</div>
            <div style={{color:"rgba(255,255,255,0.8)",fontSize:12,marginTop:2}}>{funcao}</div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <button onClick={save} style={{background:"rgba(255,255,255,0.2)",border:"2px solid rgba(255,255,255,0.4)",borderRadius:10,padding:"8px 18px",color:"#fff",fontWeight:800,cursor:"pointer",fontSize:12,whiteSpace:"nowrap"}}>
              Salvar
            </button>
            <button onClick={onClose} style={{background:"rgba(0,0,0,0.3)",border:"none",borderRadius:10,padding:"8px 14px",color:"#fff",cursor:"pointer",fontWeight:700,fontSize:16}}>✕</button>
          </div>
        </div>

        <div style={{display:"flex",gap:2,background:C.s1,padding:4,flexWrap:"wrap"}}>
          {COLLAB_TABS.filter(t=>!t.selfOnly||user.id===CURRENT_USER.id).map(t=>(
            <button key={t.id} onClick={()=>setActiveTab(t.id)}
              style={{flex:1,minWidth:80,background:activeTab===t.id?"linear-gradient(135deg,"+user.color+","+user.color+"cc)":"transparent",border:"none",padding:"10px 6px",color:activeTab===t.id?"#fff":C.ts,fontWeight:activeTab===t.id?800:500,fontSize:11,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:2,borderRadius:8}}>
              <span style={{fontSize:14}}>{t.icon}</span>
              <span>{t.label}</span>
            </button>
          ))}
        </div>

        <div style={{padding:"20px 24px",display:"flex",flexDirection:"column",gap:14}}>

          {activeTab==="dados"&&(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <div><LBL t="Nome completo"/><input value={nome} onChange={e=>setNome(e.target.value)} style={inp} placeholder="Nome completo"/></div>
            <div><LBL t="Função / Cargo"/><input value={funcao} onChange={e=>setFuncao(e.target.value)} style={inp} placeholder="Ex: Designer, Editor..."/></div>
            <div><LBL t="Telefone / WhatsApp"/><input value={telefone} onChange={e=>setTelefone(e.target.value)} style={inp} placeholder="(49) 9 9900-0000"/></div>
            <div><LBL t="Data de Nascimento"/><input type="date" value={nascimento} onChange={e=>setNascimento(e.target.value)} style={inp}/></div>
            <div style={{gridColumn:"1/-1"}}><LBL t="E-mail profissional"/><input type="email" value={email} onChange={e=>setEmail(e.target.value)} style={inp} placeholder="email@pixelsmarketing.com.br"/></div>
          </div>)}

          {activeTab==="pessoal"&&(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <div><LBL t="Cidade onde mora"/><input value={cidade} onChange={e=>setCidade(e.target.value)} style={inp} placeholder="Ex: Chapeco"/></div>
            <div><LBL t="Estado"/><select value={estado} onChange={e=>setEstado(e.target.value)} style={inp}>
              <option value="">Selecionar...</option>
              {["AC","AL","AM","AP","BA","CE","DF","ES","GO","MA","MG","MS","MT","PA","PB","PE","PI","PR","RJ","RN","RO","RR","RS","SC","SE","SP","TO"].map(s=>(<option key={s}>{s}</option>))}
            </select></div>
            <div><LBL t="Estado civil"/><select value={estadoCivil} onChange={e=>setEstadoCivil(e.target.value)} style={inp}>
              <option value="">Selecionar...</option>
              {["Solteiro(a)","Namorando","Noivo(a)","Casado(a)","Divorciado(a)","Viuvo(a)"].map(s=>(<option key={s}>{s}</option>))}
            </select></div>
            <div><LBL t="Tem filhos?"/><select value={filhos} onChange={e=>setFilhos(e.target.value)} style={inp}>
              <option value="">Selecionar...</option>
              <option>Nao</option><option>1 filho</option><option>2 filhos</option><option>3 filhos</option><option>4 ou mais</option>
            </select></div>
            <div><LBL t="Tamanho de camiseta"/><select value={camiseta} onChange={e=>setCamiseta(e.target.value)} style={inp}>
              <option value="">Selecionar...</option>
              {["PP","P","M","G","GG","XGG","XGGGG"].map(s=>(<option key={s}>{s}</option>))}
            </select></div>
            <div><LBL t="Numero de calcado"/><input value={calcado} onChange={e=>setCalcado(e.target.value)} style={inp} placeholder="Ex: 42"/></div>
            <div><LBL t="Smartphone"/><select value={smartphone} onChange={e=>setSmartphone(e.target.value)} style={inp}>
              <option value="">Selecionar...</option>
              <option>Android</option><option>iOS (iPhone)</option><option>Ambos</option>
            </select></div>
            <div><LBL t="Time que torce"/><input value={time} onChange={e=>setTime(e.target.value)} style={inp} placeholder="Ex: Chapecoense, Flamengo..."/></div>
          </div>)}

          {activeTab==="lazer"&&(<div style={{display:"flex",flexDirection:"column",gap:12}}>
            <div>
              <LBL t="5 comidas favoritas"/>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                {comidas.map((c,i)=>(<div key={i} style={{display:"flex",alignItems:"center",gap:8}}>
                  <span style={{color:C.td,fontSize:11,fontWeight:700,width:20,flexShrink:0}}>{"#"+(i+1)}</span>
                  <input value={c} onChange={e=>setComidas(v=>v.map((x,j)=>j===i?e.target.value:x))} style={inp} placeholder={"Comida favorita #"+(i+1)}/>
                </div>))}
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <div><LBL t="Bebida favorita"/><input value={bebida} onChange={e=>setBebida(e.target.value)} style={inp} placeholder="Ex: Cafe, Suco de laranja..."/></div>
              <div><LBL t="Estilo musical"/><input value={musica} onChange={e=>setMusica(e.target.value)} style={inp} placeholder="Ex: Sertanejo, Rock, Funk..."/></div>
            </div>
            <div><LBL t="Principais hobbies"/><textarea value={hobbies} onChange={e=>setHobbies(e.target.value)} rows={2} placeholder="Ex: Jogar videogame, academia, pesca, leitura..." style={{...inp,resize:"vertical",lineHeight:1.6}}/></div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <div><LBL t="Series que assiste"/><input value={series} onChange={e=>setSeries(e.target.value)} style={inp} placeholder="Ex: Breaking Bad..."/></div>
              <div><LBL t="Filmes favoritos"/><input value={filmes} onChange={e=>setFilmes(e.target.value)} style={inp} placeholder="Ex: Interestelar..."/></div>
            </div>
            <div><LBL t="Cidades/paises que ja viajou ou quer conhecer"/><textarea value={viagens} onChange={e=>setViagens(e.target.value)} rows={2} placeholder="Ex: Ja fui: Floripa, SP. Quero: Portugal, Japao..." style={{...inp,resize:"vertical",lineHeight:1.6}}/></div>
          </div>)}

          {activeTab==="pets"&&(<div style={{display:"flex",flexDirection:"column",gap:12}}>
            <div style={{color:C.ts,fontSize:12}}>Cadastre ate 10 pets.</div>
            {pets.map((pet,i)=>(<div key={i} style={{background:C.s1,borderRadius:14,padding:"14px 16px",border:"1px solid "+C.b1}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
                <div style={{color:user.color,fontWeight:800,fontSize:12}}>{"Pet #"+(i+1)}</div>
                {pets.length>1&&(<button onClick={()=>removePet(i)} style={{background:"#ff3d6b18",border:"1px solid #ff3d6b44",borderRadius:8,padding:"3px 10px",color:"#ff3d6b",fontSize:11,fontWeight:700,cursor:"pointer"}}>Remover</button>)}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div><LBL t="Você tem pet?"/><select value={pet.tem} onChange={e=>setPetField(i,"tem",e.target.value)} style={inp}>
                  <option value="">Selecionar...</option>
                  <option value="sim">Sim, tenho!</option>
                  <option value="nao">Não tenho</option>
                  <option value="quero">Não tenho, mas quero</option>
                </select></div>
                {pet.tem==="sim"&&(<>
                  <div><LBL t="Especie"/><select value={pet.especie} onChange={e=>setPetField(i,"especie",e.target.value)} style={inp}>
                    <option value="">Selecionar...</option>
                    <option>Cachorro</option><option>Gato</option><option>Passaro</option><option>Peixe</option><option>Hamster</option><option>Coelho</option><option>Outro</option>
                  </select></div>
                  <div><LBL t="Nome do pet"/><input value={pet.nome} onChange={e=>setPetField(i,"nome",e.target.value)} style={inp} placeholder="Ex: Rex, Mimi..."/></div>
                  <div><LBL t="Raca"/><input value={pet.raca} onChange={e=>setPetField(i,"raca",e.target.value)} style={inp} placeholder="Ex: Labrador, Vira-lata..."/></div>
                  <div><LBL t="Idade"/><input value={pet.idade} onChange={e=>setPetField(i,"idade",e.target.value)} style={inp} placeholder="Ex: 3 anos"/></div>
                </>)}
              </div>
            </div>))}
            {pets.length<10&&(<button onClick={addPet} style={{background:"transparent",border:"2px dashed "+user.color+"44",borderRadius:14,padding:"12px",color:user.color,fontWeight:700,fontSize:12,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
              {"+ Adicionar outro pet"}
            </button>)}
          </div>)}

          {activeTab==="curiosidades"&&(<div style={{display:"flex",flexDirection:"column",gap:12}}>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <div><LBL t="Tem algum medo ou fobia?"/><input value={medoOuFobia} onChange={e=>setMedoOuFobia(e.target.value)} style={inp} placeholder="Ex: Aranhas, altura..."/></div>
              <div><LBL t="Se tivesse um superpoder?"/><input value={superpoder} onChange={e=>setSuperpoder(e.target.value)} style={inp} placeholder="Ex: Teleporte..."/></div>
              <div><LBL t="Um talento secreto seu?"/><input value={talento} onChange={e=>setTalento(e.target.value)} style={inp} placeholder="Ex: Imitar vozes..."/></div>
              <div><LBL t="Maior licao que ja aprendeu"/><input value={licoesAprendidas} onChange={e=>setLicoesAprendidas(e.target.value)} style={inp} placeholder="Ex: Nunca desistir..."/></div>
            </div>
            <div><LBL t="Outras curiosidades sobre você"/><textarea value={curiosidades} onChange={e=>setCuriosidades(e.target.value)} rows={3} placeholder="Conte algo inusitado, divertido ou marcante sobre você..." style={{...inp,resize:"vertical",lineHeight:1.7}}/></div>
          </div>)}

          {activeTab==="bio"&&(<div style={{display:"flex",flexDirection:"column",gap:12}}>
            <div><LBL t="Sua bio (apresentação geral)"/><textarea value={bio} onChange={e=>setBio(e.target.value)} rows={4} placeholder="Apresente-se: quem e você, de onde vem..." style={{...inp,resize:"vertical",lineHeight:1.7}}/></div>
            <div><LBL t="Habilidades e ferramentas"/><textarea value={habilidades} onChange={e=>setHabilidades(e.target.value)} rows={2} placeholder="Ex: Photoshop, Premiere, Google Ads..." style={{...inp,resize:"vertical",lineHeight:1.7}}/></div>
            <div><LBL t="Objetivos profissionais"/><textarea value={objetivos} onChange={e=>setObjetivos(e.target.value)} rows={2} placeholder="O que você quer alcançar na carreira?" style={{...inp,resize:"vertical",lineHeight:1.7}}/></div>
            <div><LBL t="Observacoes gerais"/><textarea value={obs} onChange={e=>setObs(e.target.value)} rows={2} placeholder="Disponibilidade, preferencias de trabalho..." style={{...inp,resize:"vertical",lineHeight:1.7}}/></div>
          </div>)}

          {/* ═══ ABA SEGURANÇA — trocar senha (só no próprio perfil) ═══ */}
          {activeTab==="seguranca"&&user.id===CURRENT_USER.id&&(<div style={{display:"flex",flexDirection:"column",gap:16,maxWidth:500}}>
            <div style={{background:"#eff6ff",border:"1px solid #bfdbfe",borderRadius:12,padding:"14px 16px",display:"flex",gap:12,alignItems:"flex-start"}}>
              <div style={{width:36,height:36,borderRadius:10,background:"#2563eb",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>🔐</div>
              <div>
                <div style={{color:"#1e40af",fontWeight:800,fontSize:13,marginBottom:3}}>Trocar sua senha</div>
                <div style={{color:"#1e40af",fontSize:11,lineHeight:1.5}}>
                  Use uma senha forte com letras maiúsculas, minúsculas, números e símbolos. Mínimo 8 caracteres.
                </div>
              </div>
            </div>

            <div><LBL t="Senha atual"/>
              <input type={showPws?"text":"password"} value={currentPw} onChange={e=>setCurrentPw(e.target.value)}
                style={inp} placeholder="Digite sua senha atual" autoComplete="current-password"/>
            </div>

            <div><LBL t="Nova senha"/>
              <input type={showPws?"text":"password"} value={newPw} onChange={e=>setNewPw(e.target.value)}
                style={inp} placeholder="Mínimo 8 caracteres" autoComplete="new-password"/>
              {pwStrength&&<div style={{marginTop:6}}>
                <div style={{background:"#e5e7eb",borderRadius:99,height:4,overflow:"hidden"}}>
                  <div style={{width:pwStrength.pct+"%",height:"100%",background:pwStrength.color,transition:"width .3s"}}/>
                </div>
                <div style={{color:pwStrength.color,fontSize:10,fontWeight:700,marginTop:4,textTransform:"uppercase",letterSpacing:.5}}>
                  Força: {pwStrength.level}
                </div>
              </div>}
            </div>

            <div><LBL t="Confirmar nova senha"/>
              <input type={showPws?"text":"password"} value={confirmPw} onChange={e=>setConfirmPw(e.target.value)}
                style={inp} placeholder="Digite a nova senha de novo"/>
              {confirmPw&&newPw&&confirmPw!==newPw&&(
                <div style={{color:"#dc2626",fontSize:10,fontWeight:700,marginTop:4}}>⚠ As senhas não batem</div>
              )}
            </div>

            <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",color:C.ts,fontSize:12}}>
              <input type="checkbox" checked={showPws} onChange={e=>setShowPws(e.target.checked)}/>
              Mostrar senhas
            </label>

            {pwMsg&&<div style={{
              background:pwMsg.type==="success"?"#f0fdf4":"#fef2f2",
              border:`1px solid ${pwMsg.type==="success"?"#bbf7d0":"#fecaca"}`,
              color:pwMsg.type==="success"?"#166534":"#991b1b",
              borderRadius:10,padding:"10px 14px",fontSize:12,fontWeight:600}}>
              {pwMsg.text}
            </div>}

            <button onClick={handleChangePassword} disabled={pwLoading||!currentPw||!newPw||!confirmPw}
              style={{background:pwLoading||!currentPw||!newPw||!confirmPw?"#cbd5e1":"#2563eb",
                color:"#fff",border:"none",borderRadius:10,padding:"12px 0",
                fontWeight:800,fontSize:13,cursor:pwLoading||!currentPw||!newPw||!confirmPw?"not-allowed":"pointer",
                display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
              {pwLoading?"Alterando...":"🔐 Trocar senha"}
            </button>
          </div>)}

          <div style={{display:"flex",gap:10,marginTop:4,paddingTop:14,borderTop:"1px solid "+C.b1}}>
            <button onClick={onClose} style={{flex:1,background:C.b1,border:"none",borderRadius:12,padding:"11px 0",color:C.ts,fontWeight:700,cursor:"pointer",fontSize:13}}>Cancelar</button>
            <button onClick={save} style={{flex:3,background:"linear-gradient(135deg,"+user.color+","+user.color+"88)",color:"#fff",border:"none",borderRadius:12,padding:"12px 0",fontWeight:900,cursor:"pointer",fontSize:14}}>
              Salvar Perfil Completo
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ─── Constantes de nível — fora do componente ─── */
const LEVEL_LABELS={1:"Socio",2:"Coordenacao",3:"Colaborador",4:"Freelancer",5:"Cliente"};
const LEVEL_COLORS={1:C.a,2:C.pk,3:C.bl,4:C.yw,5:C.gr};

const LEVEL_FILTER_BUTTONS=[{v:0,l:"Todos"},{v:1,l:"Socio"},{v:2,l:"Coord."},{v:3,l:"Colab."},{v:4,l:"Freelancer"}];

const EMPTY_PET={tem:"",nome:"",especie:"",raca:"",idade:""};

const defaultClientAccess=(cl)=>({
  enabled:false,
  login:cl.name.toLowerCase().replace(/\s+/g,".")+".cliente",
  senha:"pixels@"+new Date().getFullYear(),
  modulos:{dashboard:true,demandas:true,calendario:true,chat:true,analises:false,faturamento:false},
  updatedAt:null,
});

const PORTAL_MODULES=[
  {id:"dashboard",   label:"Dashboard",               icon:"🎯", desc:"Visão geral da empresa"},
  {id:"demandas",    label:"Demandas",                icon:"◈",  desc:"Acompanhamento de demandas"},
  {id:"calendario",  label:"Calendário de Publicações",icon:"📅", desc:"Calendário linkado ao interno"},
  {id:"chat",        label:"Chat",                    icon:"💬", desc:"Canal exclusivo com a equipe"},
  {id:"analises",    label:"Análises",                icon:"📊", desc:"Tráfego Pago e Redes Sociais"},
  {id:"faturamento", label:"Faturamento",             icon:"💰", desc:"Contratos e faturas"},
];

const MAIN_TABS=[["equipe","👥 Equipe & Colaboradores"],["clientes","🏢 Clientes do Portal"],["storage","🗂 Storage"]];

const MEMBER_TABLE_HEADERS=["Colaborador","Função","Nível","Demandas","Status","Ações"];

const CLIENT_TABLE_HEADERS=["Cliente","Login","Portal","Módulos ativos","Ações"];

const LEVEL_STRUCTURE=[
  {l:1,name:"Socio / Dono",       c:C.a,  desc:"Acesso total, pode excluir e gerenciar tudo"},
  {l:2,name:"Coordenacao / Social Media",c:C.pk,desc:"Gerencia equipe, pode excluir cartoes"},
  {l:3,name:"Colaborador",        c:C.bl, desc:"Acessa próprio dashboard, não pode excluir"},
  {l:4,name:"Freelancer",         c:C.yw, desc:"Apenas tarefas atribuidas"},
  {l:5,name:"Cliente",            c:C.gr, desc:"Portal de aprovacoes"},
];

function PageAcessos({livePerms,setLivePerms,onViewAs,tasks}){
  const [viewUser,setViewUser]=useState(null);
  const [viewDash,setViewDash]=useState(null);
  const [editCollab,setEditCollab]=useState(null);
  const [editProfile,setEditProfile]=useState(null);

  const [search,setSearch]=useState("");
  const [filterLevel,setFilterLevel]=useState(0);
  const isMePartner=CURRENT_USER.level===1; // renomeado pra não conflitar com global isPartner(uid)
  const myPerms=withPartnerOverride({...DEFAULT_PERMS,...(ACCESS_STORE[CURRENT_USER.id]||{})}, CURRENT_USER.id);
  const [collabProfiles,setCollabProfiles]=useState(()=>{
    // Carrega perfis do localStorage como cache inicial
    const out={};
    TEAM.forEach(u=>{
      try{
        const s=localStorage.getItem("pixels-selfprofile-"+u.id);
        if(s)out[u.id]=JSON.parse(s);
      }catch(e){}
    });
    return out;
  });

  // Carregar perfis do Supabase ao montar (fonte de verdade)
  useEffect(()=>{
    const loadProfiles=async()=>{
      try{
        const sb=window._sb;
        const{data:rows}=await sb.from("profiles").select("team_id,profile_data").not("profile_data","is",null);
        if(!rows)return;
        const updates={};
        rows.forEach(row=>{
          if(row.team_id&&row.profile_data){
            updates[row.team_id]=row.profile_data;
            try{localStorage.setItem("pixels-selfprofile-"+row.team_id,JSON.stringify(row.profile_data));}catch(e){}
          }
        });
        if(Object.keys(updates).length>0){
          setCollabProfiles(p=>({...p,...updates}));
        }
      }catch(e){console.warn("Erro ao carregar perfis do Supabase:",e);}
    };
    loadProfiles();
  },[]);

  const [mainTab,setMainTab]=useState("equipe");

  const [clientAccess,setClientAccess]=useState(()=>{
    const acc={};
    CLIENTS.filter(c=>c.status!=="interno").forEach(cl=>{
      try{
        const s=localStorage.getItem("pixels-portal-access-"+cl.id);
        acc[cl.id]=s?JSON.parse(s):defaultClientAccess(cl);
      }catch(e){acc[cl.id]=defaultClientAccess(cl);}
    });
    return acc;
  });

  const [editClientId,setEditClientId]=useState(null);
  const [editClientDraft,setEditClientDraft]=useState(null);

  const saveClientAccess=(clientId,data)=>{
    const updated={...data,updatedAt:new Date().toISOString()};
    setClientAccess(p=>({...p,[clientId]:updated}));
    try{localStorage.setItem("pixels-portal-access-"+clientId,JSON.stringify(updated));}catch(e){}
  };

  const toggleClientEnabled=(clientId)=>{
    const cur=clientAccess[clientId];
    if(!cur)return;
    saveClientAccess(clientId,{...cur,enabled:!cur.enabled});
  };

  const openEditClient=(clientId)=>{
    const cur=clientAccess[clientId];
    if(!cur)return;
    setEditClientId(clientId);
    setEditClientDraft({...cur});
  };

  const saveEditClient=()=>{
    if(!editClientId||!editClientDraft)return;
    saveClientAccess(editClientId,editClientDraft);
    setEditClientId(null);setEditClientDraft(null);
  };

  // filtered team
  const allMembers=TEAM.filter(u=>{
    const matchSearch=search===""||u.name.toLowerCase().includes(search.toLowerCase())||u.role.toLowerCase().includes(search.toLowerCase());
    const matchLevel=filterLevel===0||u.level===filterLevel;
    return matchSearch&&matchLevel;
  });

  const taskCount=(uid)=>(tasks||[]).filter(t=>t.assignee===uid&&!t.deletedAt).length;
  const doneCount=(uid)=>(tasks||[]).filter(t=>t.assignee===uid&&!t.deletedAt&&t.status==="aprovado").length;

  if(viewDash){
    const u=TEAM.find(x=>x.id===viewDash);
    if(!u)return null;
    return <div style={{display:"flex",flexDirection:"column",gap:0}}>
      <button onClick={()=>setViewDash(null)} style={{background:C.b1,border:"none",borderRadius:10,padding:"9px 16px",color:C.ts,cursor:"pointer",fontSize:12,fontWeight:700,alignSelf:"flex-start",marginBottom:16}}>{"<- Voltar"}</button>
      <RenderDash user={u} isViewing={true} tasks={tasks||[]} setTasks={()=>{}}/>
    </div>;
  }

  if(viewUser)return <div style={{display:"flex",flexDirection:"column",gap:0}}>
    <button onClick={()=>setViewUser(null)} style={{background:C.b1,border:"none",borderRadius:10,padding:"9px 16px",color:C.ts,cursor:"pointer",fontSize:12,fontWeight:700,alignSelf:"flex-start",marginBottom:16}}>{"<- Voltar"}</button>
    <RenderDash user={viewUser} isViewing={true} tasks={tasks||[]} setTasks={()=>{}}/>
  </div>;

  const collabUser=editCollab?TEAM.find(u=>u.id===editCollab):null;
  const profileUser=editProfile?TEAM.find(u=>u.id===editProfile):null;

  return (<>
    {collabUser&&(<CollabProfileModal user={collabUser} onClose={()=>setEditCollab(null)} livePerms={livePerms} setLivePerms={setLivePerms} tasks={tasks}/>)}
    {profileUser&&(<CollabProfilePage
      user={profileUser}
      profile={collabProfiles[editProfile]}
      onSave={async(uid,data)=>{
        setCollabProfiles(p=>({...p,[uid]:data}));
        try{localStorage.setItem("pixels-selfprofile-"+uid,JSON.stringify(data));}catch(e){}
        // Salvar no Supabase para persistência permanente
        try{
          const sb=window._sb;
          const{data:profileRow}=await sb.from("profiles").select("id").eq("team_id",uid).single();
          if(profileRow){
            await sb.from("profiles").update({profile_data:data}).eq("id",profileRow.id);
          }
        }catch(e){console.warn("Erro ao salvar perfil no Supabase:",e);}
      }}
      onClose={()=>setEditProfile(null)}
    />)}

    {/* ── CLIENT ACCESS EDIT MODAL ── */}
    {editClientId&&editClientDraft&&(()=>{
      const cl=CLIENTS.find(c=>c.id===editClientId);
      if(!cl)return null;
      const inp={background:C.s1,border:"1px solid "+C.b1,borderRadius:8,padding:"8px 10px",color:C.tx,fontSize:13,outline:"none",width:"100%",boxSizing:"border-box",fontFamily:"inherit"};
      return(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.88)",zIndex:300,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={()=>setEditClientId(null)}>
          <div onClick={e=>e.stopPropagation()} style={{background:C.card,borderRadius:20,width:"100%",maxWidth:560,border:"2px solid "+cl.color,boxShadow:"0 0 60px "+cl.color+"30",overflow:"hidden"}}>
            {/* Header */}
            <div style={{background:"linear-gradient(135deg,"+cl.color+","+cl.color+"88)",padding:"18px 22px",display:"flex",alignItems:"center",gap:14}}>
              <div style={{width:44,height:44,borderRadius:12,background:"rgba(255,255,255,0.2)",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:900,fontSize:18}}>{cl.name.slice(0,2).toUpperCase()}</div>
              <div style={{flex:1}}>
                <div style={{color:"#fff",fontWeight:900,fontSize:16}}>{cl.name}</div>
                <div style={{color:"rgba(255,255,255,0.75)",fontSize:11,marginTop:2}}>Gerenciar acesso ao portal</div>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{display:"flex",alignItems:"center",gap:6,background:"rgba(255,255,255,0.15)",borderRadius:20,padding:"5px 12px"}}>
                  <span style={{color:"#fff",fontSize:11,fontWeight:600}}>Portal</span>
                  <div onClick={()=>setEditClientDraft(d=>({...d,enabled:!d.enabled}))}
                    style={{width:36,height:20,borderRadius:99,background:editClientDraft.enabled?"#22c55e":"rgba(255,255,255,0.3)",cursor:"pointer",position:"relative",transition:"background .2s"}}>
                    <div style={{position:"absolute",top:2,left:editClientDraft.enabled?18:2,width:16,height:16,borderRadius:"50%",background:"#fff",transition:"left .2s"}}/>
                  </div>
                  <span style={{color:editClientDraft.enabled?"#86efac":"rgba(255,255,255,0.6)",fontSize:10,fontWeight:700}}>{editClientDraft.enabled?"Ativo":"Inativo"}</span>
                </div>
              </div>
            </div>

            <div style={{padding:"18px 22px",display:"flex",flexDirection:"column",gap:16,maxHeight:"68vh",overflowY:"auto"}}>
              {/* Login credentials */}
              <div>
                <div style={{color:C.ts,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.8,marginBottom:8}}>🔑 Credenciais de Acesso</div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                  <div>
                    <div style={{color:C.td,fontSize:10,marginBottom:4}}>Login</div>
                    <input value={editClientDraft.login||""} onChange={e=>setEditClientDraft(d=>({...d,login:e.target.value}))} style={inp} placeholder="login.do.cliente"/>
                  </div>
                  <div>
                    <div style={{color:C.td,fontSize:10,marginBottom:4}}>Senha</div>
                    <input value={editClientDraft.senha||""} onChange={e=>setEditClientDraft(d=>({...d,senha:e.target.value}))} style={inp} placeholder="Senha de acesso"/>
                  </div>
                </div>
                <div style={{background:C.s1,borderRadius:8,padding:"8px 12px",marginTop:6,fontSize:10,color:C.td,lineHeight:1.6}}>
                  ⚠ As credenciais são exibidas aqui para controle interno. Compartilhe com o cliente de forma segura.
                </div>
              </div>

              {/* Module permissions */}
              <div>
                <div style={{color:C.ts,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.8,marginBottom:10}}>📋 Módulos do Portal</div>
                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  {PORTAL_MODULES.map(mod=>{
                    const on=editClientDraft.modulos?.[mod.id]||false;
                    return(
                      <div key={mod.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 12px",background:on?cl.color+"10":C.s1,borderRadius:10,border:"1px solid "+(on?cl.color+"44":C.b1),transition:"all .15s"}}>
                        <div style={{display:"flex",alignItems:"center",gap:8}}>
                          <span style={{fontSize:16}}>{mod.icon}</span>
                          <div>
                            <div style={{color:on?C.tx:C.ts,fontSize:12,fontWeight:on?700:500}}>{mod.label}</div>
                            <div style={{color:C.td,fontSize:10}}>{mod.desc}</div>
                          </div>
                        </div>
                        <div onClick={()=>setEditClientDraft(d=>({...d,modulos:{...d.modulos,[mod.id]:!on}}))}
                          style={{width:38,height:22,borderRadius:99,background:on?cl.color:C.b2,cursor:"pointer",position:"relative",transition:"background .2s",flexShrink:0}}>
                          <div style={{position:"absolute",top:3,left:on?18:3,width:16,height:16,borderRadius:"50%",background:"#fff",transition:"left .2s"}}/>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Actions */}
              <div style={{display:"flex",gap:8,paddingTop:4,borderTop:"1px solid "+C.b1}}>
                <button onClick={()=>setEditClientId(null)} style={{flex:1,background:C.s1,border:"1px solid "+C.b1,borderRadius:10,padding:"10px",color:C.ts,fontWeight:700,cursor:"pointer",fontSize:13}}>Cancelar</button>
                <button onClick={saveEditClient} style={{flex:2,background:"linear-gradient(135deg,"+cl.color+","+cl.color+"cc)",color:"#fff",border:"none",borderRadius:10,padding:"10px",fontWeight:900,cursor:"pointer",fontSize:13}}>
                  💾 Salvar Configurações
                </button>
              </div>
            </div>
          </div>
        </div>
      );
    })()}

    <div style={{display:"flex",flexDirection:"column",gap:20}}>

      {/* ── MAIN TAB SWITCHER ── */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:12}}>
        <div style={{display:"flex",gap:3,background:C.s1,borderRadius:12,padding:3}}>
          {MAIN_TABS.map(([id,lbl])=>(
            <button key={id} onClick={()=>setMainTab(id)}
              style={{background:mainTab===id?"linear-gradient(135deg,"+C.a+","+C.aD+")":"transparent",color:mainTab===id?"#fff":C.ts,border:"none",borderRadius:9,padding:"9px 20px",fontWeight:mainTab===id?700:400,fontSize:13,cursor:"pointer",transition:"all .15s"}}>
              {lbl}
            </button>
          ))}
        </div>
        {mainTab==="equipe"&&<div style={{color:C.ts,fontSize:12}}>{TEAM.length} membros · {TEAM.filter(u=>u.status==="online").length} online</div>}
        {mainTab==="clientes"&&<div style={{color:C.ts,fontSize:12}}>{CLIENTS.filter(c=>c.status!=="interno").filter(c=>clientAccess[c.id]?.enabled).length} portais ativos</div>}
      </div>

      {/* ══ EQUIPE ══ */}
      {mainTab==="equipe"&&<>
        <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
          <div style={{position:"relative"}}>
            <span style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",color:C.td,fontSize:13,pointerEvents:"none"}}>🔍</span>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Buscar colaborador..."
              style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:10,padding:"8px 12px 8px 32px",color:C.tx,fontSize:12,outline:"none",width:200,fontFamily:"inherit"}}/>
          </div>
          <div style={{display:"flex",gap:4,background:C.s1,borderRadius:10,padding:3}}>
            {LEVEL_FILTER_BUTTONS.map(item=>(
              <button key={item.v} onClick={()=>setFilterLevel(item.v)}
                style={{background:filterLevel===item.v?(LEVEL_COLORS[item.v]||C.a):"transparent",border:"none",borderRadius:7,padding:"5px 10px",color:filterLevel===item.v?"#fff":C.ts,fontWeight:filterLevel===item.v?700:400,fontSize:11,cursor:"pointer",whiteSpace:"nowrap",transition:"all .15s"}}>
                {item.l}
              </button>
            ))}
          </div>
        </div>

      <div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,overflow:"hidden"}}>
        <div style={{display:"grid",gridTemplateColumns:"2.5fr 1.5fr 1fr 1fr 1fr 120px",gap:0,padding:"10px 20px",background:C.s1,borderBottom:"1px solid "+C.b1}}>
          {MEMBER_TABLE_HEADERS.map((h,i)=>(
            <div key={h} style={{color:C.td,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.8,textAlign:i>=3?"center":"left"}}>{h}</div>
          ))}
        </div>

        {allMembers.map((u,idx)=>{
          const lvColor=LEVEL_COLORS[u.level]||C.ts;
          const lvLabel=LEVEL_LABELS[u.level]||"—";
          const tc=taskCount(u.id);
          const dc=doneCount(u.id);
          const photo=collabProfiles[u.id]?.photo;
          const isLast=idx===allMembers.length-1;
          return (<div key={u.id}
            style={{display:"grid",gridTemplateColumns:"2.5fr 1.5fr 1fr 1fr 1fr 120px",gap:0,padding:"14px 20px",borderBottom:isLast?"none":"1px solid "+C.b1+"44",alignItems:"center",transition:"background .12s",cursor:"default"}}
            onMouseEnter={e=>{e.currentTarget.style.background=C.s1;}}
            onMouseLeave={e=>{e.currentTarget.style.background="transparent";}}>

            <div style={{display:"flex",alignItems:"center",gap:12}}>
              <div style={{width:38,height:38,borderRadius:12,overflow:"hidden",flexShrink:0,border:"1.5px solid "+u.color+"44"}}>
                {photo
                  ?(<img src={photo} alt={u.name} style={{width:"100%",height:"100%",objectFit:"cover"}}/>)
                  :(<div style={{width:"100%",height:"100%",background:"linear-gradient(135deg,"+u.color+"33,"+u.color+"11)",display:"flex",alignItems:"center",justifyContent:"center",color:u.color,fontWeight:900,fontSize:15}}>{u.av}</div>)
                }
              </div>
              <div>
                <div style={{color:C.tx,fontWeight:700,fontSize:13}}>{collabProfiles[u.id]?.nome||u.name}</div>
                <div style={{color:C.td,fontSize:11,marginTop:1}}>{u.id+"@pixelsmarketing.com.br"}</div>
              </div>
            </div>

            <div style={{color:C.ts,fontSize:12}}>{u.role}</div>

            <div>
              <span style={{background:lvColor+"18",color:lvColor,borderRadius:6,padding:"3px 9px",fontSize:10,fontWeight:700}}>{lvLabel}</span>
            </div>

            <div style={{textAlign:"center"}}>
              <div style={{color:C.tx,fontWeight:700,fontSize:13}}>{tc}</div>
              <div style={{color:C.td,fontSize:10,marginTop:1}}>{dc+" concluidas"}</div>
            </div>

            <div style={{textAlign:"center"}}>
              <span style={{display:"inline-flex",alignItems:"center",gap:5,background:u.status==="online"?C.gr+"18":C.td+"18",color:u.status==="online"?C.gr:C.td,borderRadius:99,padding:"3px 10px",fontSize:10,fontWeight:700}}>
                <span style={{width:5,height:5,borderRadius:"50%",background:u.status==="online"?C.gr:C.td,flexShrink:0}}/>
                {u.status==="online"?"Online":"Ausente"}
              </span>
            </div>

            <div style={{display:"flex",gap:4,alignItems:"center",justifyContent:"flex-end"}}>
              <button onClick={()=>u.level===1?setViewDash(u.id):setViewUser(u)}
                title="Ver dashboard" style={{background:"none",border:"1px solid "+C.b1,borderRadius:8,width:30,height:30,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:13,color:C.ts}}
                onMouseEnter={e=>{e.currentTarget.style.background=u.color+"18";e.currentTarget.style.color=u.color;}}
                onMouseLeave={e=>{e.currentTarget.style.background="none";e.currentTarget.style.color=C.ts;}}>
                🎯
              </button>
              <button onClick={()=>setEditProfile(u.id)}
                title="Editar perfil" style={{background:"none",border:"1px solid "+C.b1,borderRadius:8,width:30,height:30,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:13,color:C.ts}}
                onMouseEnter={e=>{e.currentTarget.style.background=u.color+"18";e.currentTarget.style.color=u.color;}}
                onMouseLeave={e=>{e.currentTarget.style.background="none";e.currentTarget.style.color=C.ts;}}>
                👤
              </button>
              {(isMePartner||myPerms?.verDashOutros)&&(<button onClick={()=>onViewAs&&onViewAs(u.id)}
                title={"Ver como "+u.name} style={{background:"none",border:"1px solid "+C.b1,borderRadius:8,width:30,height:30,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:13,color:C.ts}}
                onMouseEnter={e=>{e.currentTarget.style.background=C.or+"18";e.currentTarget.style.color=C.or;}}
                onMouseLeave={e=>{e.currentTarget.style.background="none";e.currentTarget.style.color=C.ts;}}>
                👁
              </button>)}
              {isMePartner&&(<button onClick={()=>setEditCollab(u.id)}
                title="Gerenciar permissoes" style={{background:"none",border:"1px solid "+C.b1,borderRadius:8,width:30,height:30,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:13,color:C.ts}}
                onMouseEnter={e=>{e.currentTarget.style.background=C.a+"18";e.currentTarget.style.color=C.a;}}
                onMouseLeave={e=>{e.currentTarget.style.background="none";e.currentTarget.style.color=C.ts;}}>
                ⚙
              </button>)}
            </div>
          </div>);
        })}

        {allMembers.length===0&&(<div style={{padding:"40px",textAlign:"center",color:C.td,fontSize:13}}>Nenhum colaborador encontrado.</div>)}
      </div>

      {isPartner&&(<div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,overflow:"hidden"}}>
        <div style={{padding:"14px 20px",borderBottom:"1px solid "+C.b1,display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:14}}>🔒</span>
          <div style={{color:C.tx,fontWeight:700,fontSize:13}}>Estrutura de Niveis</div>
          <div style={{color:C.td,fontSize:11,marginLeft:4}}>Visivel apenas para socios</div>
        </div>
        <div style={{padding:"6px 0"}}>
          {LEVEL_STRUCTURE.map((lv,idx,arr)=>{
            const members=TEAM.filter(m=>m.level===lv.l);
            return (<div key={lv.l} style={{display:"flex",alignItems:"center",gap:16,padding:"12px 20px",borderBottom:idx<arr.length-1?"1px solid "+C.b1+"44":"none"}}>
              <div style={{width:28,height:28,borderRadius:8,background:lv.c+"22",border:"1.5px solid "+lv.c+"44",display:"flex",alignItems:"center",justifyContent:"center",color:lv.c,fontWeight:800,fontSize:12,flexShrink:0}}>{lv.l}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{color:C.tx,fontWeight:600,fontSize:13}}>{lv.name}</div>
                <div style={{color:C.td,fontSize:11,marginTop:1}}>{lv.desc}</div>
              </div>
              <div style={{display:"flex",alignItems:"center"}}>
                {members.length===0&&(<span style={{color:C.td,fontSize:11}}>—</span>)}
                {members.map((m,i)=>{
                  const ph=collabProfiles[m.id]?.photo;
                  return (<div key={m.id} title={m.name} style={{width:26,height:26,borderRadius:"50%",overflow:"hidden",border:"2px solid "+C.card,marginLeft:i>0?-8:0,cursor:"pointer"}} onClick={()=>setEditProfile(m.id)}>
                    {ph?(<img src={ph} alt={m.name} style={{width:"100%",height:"100%",objectFit:"cover"}}/>)
                      :(<div style={{width:"100%",height:"100%",background:m.color+"33",display:"flex",alignItems:"center",justifyContent:"center",color:m.color,fontWeight:900,fontSize:10}}>{m.av}</div>)}
                  </div>);
                })}
                {members.length>0&&(<span style={{color:C.td,fontSize:11,marginLeft:12}}>{members.length+" membro"+(members.length!==1?"s":"")}</span>)}
              </div>
            </div>);
          })}
        </div>
      </div>)}
      </>}

      {/* ══ CLIENTES DO PORTAL ══ */}
      {mainTab==="clientes"&&(
        <div style={{display:"flex",flexDirection:"column",gap:14}}>

          {/* Info box */}
          <div style={{background:C.a+"0a",border:"1px solid "+C.a+"22",borderRadius:12,padding:"12px 16px",fontSize:12,color:C.ts,lineHeight:1.6}}>
            <strong style={{color:C.tx}}>🏢 Portal do Cliente</strong> — Gerencie os acessos individuais de cada empresa. Cada cliente entra no portal e visualiza somente os dados da própria empresa. Configure quais módulos cada um pode acessar.
          </div>

          {/* Client list */}
          <div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,overflow:"hidden"}}>
            <div style={{display:"grid",gridTemplateColumns:"2fr 1.5fr 1fr 2fr 100px",padding:"10px 20px",background:C.s1,borderBottom:"1px solid "+C.b1}}>
              {CLIENT_TABLE_HEADERS.map((h,i)=>(
                <div key={h} style={{color:C.td,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.8,textAlign:i>=2?"center":"left"}}>{h}</div>
              ))}
            </div>

            {CLIENTS.filter(c=>c.status!=="interno").map((cl,idx,arr)=>{
              const acc=clientAccess[cl.id]||defaultClientAccess(cl);
              const activeMods=PORTAL_MODULES.filter(m=>acc.modulos?.[m.id]);
              return(
                <div key={cl.id}
                  style={{display:"grid",gridTemplateColumns:"2fr 1.5fr 1fr 2fr 100px",padding:"14px 20px",borderBottom:idx<arr.length-1?"1px solid "+C.b1+"44":"none",alignItems:"center",transition:"background .12s"}}
                  onMouseEnter={e=>e.currentTarget.style.background=C.s1}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>

                  {/* Client name */}
                  <div style={{display:"flex",alignItems:"center",gap:10}}>
                    <div style={{width:36,height:36,borderRadius:10,background:cl.color+"18",border:"1px solid "+cl.color+"33",display:"flex",alignItems:"center",justifyContent:"center",color:cl.color,fontWeight:900,fontSize:13,flexShrink:0}}>
                      {cl.name.slice(0,2).toUpperCase()}
                    </div>
                    <div>
                      <div style={{color:C.tx,fontWeight:700,fontSize:13}}>{cl.name}</div>
                      <div style={{color:C.td,fontSize:10}}>{cl.sector}</div>
                    </div>
                  </div>

                  {/* Login */}
                  <div>
                    <div style={{color:C.ts,fontSize:11,fontFamily:"monospace"}}>{acc.login||"—"}</div>
                    {acc.updatedAt&&<div style={{color:C.td,fontSize:9,marginTop:2}}>Atualizado {new Date(acc.updatedAt).toLocaleDateString("pt-BR")}</div>}
                  </div>

                  {/* Status toggle */}
                  <div style={{display:"flex",justifyContent:"center"}}>
                    <div onClick={()=>isPartner&&toggleClientEnabled(cl.id)}
                      style={{display:"flex",alignItems:"center",gap:5,background:acc.enabled?C.gr+"18":C.b1,border:"1px solid "+(acc.enabled?C.gr+"44":C.b1),borderRadius:20,padding:"5px 10px",cursor:isPartner?"pointer":"default"}}>
                      <div style={{width:7,height:7,borderRadius:"50%",background:acc.enabled?C.gr:C.td}}/>
                      <span style={{color:acc.enabled?C.gr:C.td,fontSize:10,fontWeight:700}}>{acc.enabled?"Ativo":"Inativo"}</span>
                    </div>
                  </div>

                  {/* Active modules */}
                  <div style={{display:"flex",gap:4,flexWrap:"wrap",justifyContent:"center"}}>
                    {activeMods.length===0
                      ?<span style={{color:C.td,fontSize:10}}>Nenhum</span>
                      :activeMods.map(m=>(
                        <span key={m.id} style={{background:cl.color+"14",color:cl.color,borderRadius:5,padding:"1px 7px",fontSize:9,fontWeight:700}}>{m.icon} {m.label}</span>
                      ))
                    }
                  </div>

                  {/* Actions */}
                  <div style={{display:"flex",gap:5,justifyContent:"flex-end"}}>
                    {isPartner&&(
                      <button onClick={()=>openEditClient(cl.id)} title="Configurar acesso"
                        style={{background:"none",border:"1px solid "+C.b1,borderRadius:8,width:30,height:30,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:13,color:C.ts}}
                        onMouseEnter={e=>{e.currentTarget.style.background=cl.color+"18";e.currentTarget.style.color=cl.color;}}
                        onMouseLeave={e=>{e.currentTarget.style.background="none";e.currentTarget.style.color=C.ts;}}>
                        ⚙
                      </button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          {/* Portal modules legend */}
          <div style={{background:C.card,borderRadius:14,border:"1px solid "+C.b1,padding:"14px 18px"}}>
            <div style={{color:C.ts,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.8,marginBottom:10}}>Estrutura do Portal</div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:8}}>
              {PORTAL_MODULES.map(m=>(
                <div key={m.id} style={{background:C.s1,borderRadius:10,padding:"10px 12px",display:"flex",alignItems:"center",gap:8}}>
                  <span style={{fontSize:18}}>{m.icon}</span>
                  <div>
                    <div style={{color:C.tx,fontWeight:700,fontSize:12}}>{m.label}</div>
                    <div style={{color:C.td,fontSize:10}}>{m.desc}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Tab Storage — só admins */}
      {mainTab==="storage"&&isPartner&&<StorageManager tasks={tasks}/>}

    </div>
  </>);
}

/* ─── STORAGE MANAGER ─────────────────────────── */
function StorageManager({tasks}){
  const [scanning,setScanning]=useState(false);
  const [orphans,setOrphans]=useState(null); // null=não escaneado, []=escaneado
  const [deleting,setDeleting]=useState(false);
  const [log,setLog]=useState([]);

  const scan=async()=>{
    setScanning(true);
    setOrphans(null);
    setLog([]);
    try{
      const sb=window._sb;

      // 1. Coletar todos os storagePaths válidos de tasks ativos + lixeira
      const validPaths=new Set();
      (tasks||[]).forEach(t=>{
        (t.files||[]).forEach(f=>{
          if(f.storagePath)validPaths.add(f.storagePath);
        });
      });

      // 2. Listar arquivos no bucket — pasta tasks/
      const{data:items,error}=await sb.storage.from("pixels-files").list("tasks",{limit:1000,offset:0});
      if(error)throw error;

      // 3. Para cada subpasta (id do task), listar arquivos
      const found=[];
      for(const folder of (items||[])){
        const{data:files}=await sb.storage.from("pixels-files").list(`tasks/${folder.name}`,{limit:100});
        for(const file of (files||[])){
          const path=`tasks/${folder.name}/${file.name}`;
          if(!validPaths.has(path)){
            found.push({path,name:file.name,folder:folder.name,size:file.metadata?.size||0});
          }
        }
      }
      setOrphans(found);
    }catch(e){
      setLog([`Erro ao escanear: ${e.message}`]);
    }
    setScanning(false);
  };

  const deleteOrphans=async()=>{
    if(!orphans||orphans.length===0)return;
    setDeleting(true);
    const newLog=[];
    try{
      const sb=window._sb;
      const paths=orphans.map(o=>o.path);
      const{error}=await sb.storage.from("pixels-files").remove(paths);
      if(error)throw error;
      newLog.push(`✅ ${paths.length} arquivo(s) deletado(s) com sucesso.`);
      setOrphans([]);
    }catch(e){
      newLog.push(`❌ Erro ao deletar: ${e.message}`);
    }
    setLog(newLog);
    setDeleting(false);
  };

  const fmtSize=b=>b>1048576?(b/1048576).toFixed(1)+"MB":b>1024?(b/1024).toFixed(0)+"KB":b+"B";

  return <div style={{display:"flex",flexDirection:"column",gap:16}}>
    {/* Header */}
    <div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,padding:"18px 20px"}}>
      <div style={{color:C.tx,fontWeight:800,fontSize:16,marginBottom:4}}>🗂 Gerenciador de Storage</div>
      <div style={{color:C.ts,fontSize:12}}>Escaneia o bucket <strong>pixels-files</strong> e identifica arquivos órfãos — arquivos que não pertencem a nenhum cartão ativo ou na lixeira.</div>
    </div>

    {/* Aviso */}
    <div style={{background:C.yw+"18",border:"1px solid "+C.yw+"44",borderRadius:12,padding:"12px 16px",display:"flex",gap:10,alignItems:"flex-start"}}>
      <span style={{fontSize:18}}>⚠️</span>
      <div style={{color:C.ts,fontSize:12}}>
        <strong style={{color:C.tx}}>Atenção:</strong> Revise a lista antes de deletar. Esta ação é <strong>irreversível</strong>. Arquivos de cartões na lixeira são preservados.
      </div>
    </div>

    {/* Botão escanear */}
    <button onClick={scan} disabled={scanning||deleting}
      style={{background:C.a,color:"#fff",border:"none",borderRadius:12,padding:"12px 24px",fontWeight:700,fontSize:14,cursor:scanning?"wait":"pointer",opacity:scanning?0.7:1,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
      {scanning?"⏳ Escaneando bucket...":"🔍 Escanear Storage"}
    </button>

    {/* Resultado */}
    {orphans!==null&&<div style={{background:C.card,borderRadius:14,border:"1px solid "+C.b1,overflow:"hidden"}}>
      <div style={{padding:"14px 18px",borderBottom:"1px solid "+C.b1,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <span style={{color:C.tx,fontWeight:700,fontSize:14}}>
            {orphans.length===0?"✅ Nenhum arquivo órfão encontrado":`🗑 ${orphans.length} arquivo(s) órfão(s) encontrado(s)`}
          </span>
          {orphans.length>0&&<div style={{color:C.ts,fontSize:11,marginTop:2}}>
            Total: {fmtSize(orphans.reduce((s,o)=>s+o.size,0))}
          </div>}
        </div>
        {orphans.length>0&&<button onClick={async()=>{if(await pixelsConfirm(`Deletar permanentemente ${orphans.length} arquivo(s) órfão(s)? Esta ação não pode ser desfeita.`,{okText:"Deletar",danger:true}))deleteOrphans();}}
          disabled={deleting}
          style={{background:C.rd,color:"#fff",border:"none",borderRadius:9,padding:"8px 18px",fontWeight:700,fontSize:12,cursor:deleting?"wait":"pointer",opacity:deleting?0.7:1}}>
          {deleting?"⏳ Deletando...":"🗑 Deletar todos os órfãos"}
        </button>}
      </div>

      {orphans.length>0&&<div style={{maxHeight:320,overflowY:"auto"}}>
        {orphans.map((o,i)=>(
          <div key={o.path} style={{padding:"10px 18px",borderBottom:i<orphans.length-1?"1px solid "+C.b1+"44":"none",display:"flex",justifyContent:"space-between",alignItems:"center",gap:12}}>
            <div style={{minWidth:0}}>
              <div style={{color:C.tx,fontSize:12,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{o.name}</div>
              <div style={{color:C.td,fontSize:10,marginTop:2}}>tasks/{o.folder}/</div>
            </div>
            <span style={{color:C.ts,fontSize:11,flexShrink:0}}>{fmtSize(o.size)}</span>
          </div>
        ))}
      </div>}
    </div>}


    {/* Log */}
    {log.length>0&&<div style={{background:C.s1,borderRadius:10,padding:"12px 16px"}}>
      {log.map((l,i)=><div key={i} style={{color:C.ts,fontSize:12}}>{l}</div>)}
    </div>}
  </div>;
}

